diff --git a/packages/coding-agent/src/utils/clipboard-native.ts b/packages/coding-agent/src/utils/clipboard-native.ts
new file mode 100644
index 0000000000..e176d47c33
--- /dev/null
+++ b/packages/coding-agent/src/utils/clipboard-native.ts
@@ -0,0 +1,21 @@
+import { createRequire } from "module";
+
+export type ClipboardModule = {
+	hasImage: () => boolean;
+	getImageBinary: () => Promise<Array<number>>;
+};
+
+const require = createRequire(import.meta.url);
+let clipboard: ClipboardModule | null = null;
+
+const hasDisplay = process.platform !== "linux" || Boolean(process.env.DISPLAY || process.env.WAYLAND_DISPLAY);
+
+if (!process.env.TERMUX_VERSION && hasDisplay) {
+	try {
+		clipboard = require("@mariozechner/clipboard") as ClipboardModule;
+	} catch {
+		clipboard = null;
+	}
+}
+
+export { clipboard };
